// criando variáveis
let primeiroValor = 70;
let segundoValor = 50;
let resultado;

// maior que
resultado = primeiroValor > segundoValor;
console.log(`${primeiroValor} > ${segundoValor} = ${resultado}`);

// menor que
resultado = primeiroValor < segundoValor;
console.log(`${primeiroValor} < ${segundoValor} = ${resultado}`);

// maior ou igual a
resultado = primeiroValor >= segundoValor;
console.log(`${primeiroValor} >= ${segundoValor} = ${resultado}`);

// menor ou igual a
resultado = primeiroValor <= segundoValor;
console.log(`${primeiroValor} <= ${segundoValor} = ${resultado}`);

// igual a
resultado = primeiroValor == segundoValor;
console.log(`${primeiroValor} == ${segundoValor} = ${resultado}`);

// diferente de
resultado = primeiroValor != segundoValor;
console.log(`${primeiroValor} != ${segundoValor} = ${resultado}`);

// convertendo o segundo valor para string
segundoValor = '50';

// estritamente igual a
resultado = primeiroValor === segundoValor;
console.log(`${primeiroValor} === ${segundoValor} = ${resultado}`);

// estritamente diferente de
resultado = primeiroValor !== segundoValor;
console.log(`${primeiroValor} !== ${segundoValor} = ${resultado}`);

